arguments.argument:
if oKeyCodes.kCodePressed[5]=1
{
  if currentPage>1
  {
    playSound(global.snd_PageFlip,0,0.95,1)
    image_alpha=0
    currentPage-=1
  }
}
if oKeyCodes.kCodePressed[6]=1 or keyboard_check_pressed(vk_enter)
{
  if currentPage<13 {playSound(global.snd_PageFlip,0,0.95,1)}
  image_alpha=0
  currentPage+=1
  if currentPage=14
  {
    room_goto(rTitle)
  }
}
else if oKeyCodes.kCodePressed[7]=1
{
  room_goto(rTitle)
}

if image_alpha<1 {image_alpha+=0.025}
